#include <stdio.h>
#include <math.h>
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N, R, D, L;
        scanf("%d %d %d %d", &N, &R, &D, &L);
        double x[N], y[N];
        for (int i = 0; i < N; i++) {
            scanf("%lf %lf", &x[i], &y[i]);
        }
        double area = (2 * L) * (2 * L);
        for (int i = 0; i < N; i++) {
            double angle = acos((D * D + R * R - R * R) / (2 * D * R));
            area -= (angle / (2 * M_PI)) * M_PI * R * R;
        }
        printf("%.10f\n", area);
    }
    return 0;
}

