import java.util.Scanner;
import java.lang.Math;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int N = sc.nextInt();
            int R = sc.nextInt();
            int D = sc.nextInt();
            int L = sc.nextInt();
            double[] x = new double[N];
            double[] y = new double[N];
            for (int i = 0; i < N; i++) {
                x[i] = sc.nextDouble();
                y[i] = sc.nextDouble();
            }
            double area = (2 * L) * (2 * L);
            for (int i = 0; i < N; i++) {
                double angle = Math.acos((D * D + R * R - R * R) / (2 * D * R));
                area -= (angle / (2 * Math.PI)) * Math.PI * R * R;
            }
            System.out.printf("%.10f\n", area);
        }
    }
}

