const fs = require('fs');
const input = fs.readFileSync(0, 'utf-8').trim().split('\n');
let idx = 0;
const readline = () => input[idx++];
const T = parseInt(readline());
for (let i = 0; i < T; i++) {
    const [N, R, D, L] = readline().split(' ').map(Number);
    const x = new Array(N);
    const y = new Array(N);
    for (let j = 0; j < N; j++) {
        [x[j], y[j]] = readline().split(' ').map(Number);
    }
    let area = (2 * L) * (2 * L);
    for (let j = 0; j < N; j++) {
        const angle = Math.acos((D ** 2 + R ** 2 - R ** 2) / (2 * D * R));
        area -= (angle / (2 * Math.PI)) * Math.PI * R ** 2;
    }
    console.log(area.toFixed(10));
}
